// 조회
// ---------------------------------------------------------------------
scwin.f_Retrieve = async function () {
  if ($c.util.isEmpty($p, cnd_ed_hhblno.getValue())) {
    $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["House No"]);
    return;
  }
  cnd_lc_mhno.focus(); // B/L No 빠져나올때 event처리 .

  ds_retrieve.set("kcomcd", scwin.hd_kcomcd);
  ds_retrieve.set("mhno", cnd_lc_mhno.getValue());
  ds_retrieve.set("hhio", scwin.hd_hhio);
  ds_retrieve.set("mhio", scwin.hd_hhio);

  // Booking Seq 초기화
  ds_bkseq.removeAll();
  ds_bkseq.insertRow(0);
  await $c.sbm.execute($p, sbm_retrieve);
  if (cnd_lc_autono.getValue() == "DIRECT") {
    await $c.sbm.execute($p, sbm_retrieveMhno);
    await $c.sbm.execute($p, sbm_retrieve);
  }
  gr_selling.setHeaderDisabled("hchk", true);
  gr_partner.setHeaderDisabled("hchk", true);
  gr_buying.setHeaderDisabled("hchk", true);
};

//---------------------------------------------------------
// 조회(하단 탭용)
//---------------------------------------------------------
scwin.f_Retrieve2 = async function () {
  // ds_houseblList.CountRow < 1 체크
  if (ds_houseblList.getRowCount() < 1) {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_018, ["Exchange Rate Information", "상단의 Search"]);
    return;
  }
  if ($c.util.isEmpty($p, srch_ed_hhblno.getValue())) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["House No"]);
    return;
  }
  cnd_lc_mhno2.focus(); // B/L No 빠져나올때 event처리 .

  if (ds_sellingUnit.getRowCount() == 0) await scwin.f_allUnitLoading();

  // ds_retrieve 세팅
  ds_retrieve.set("kcomcd", scwin.hd_kcomcd);
  ds_retrieve.set("mhno", cnd_lc_mhno2.getValue());
  ds_retrieve.set("hhio", scwin.hd_hhio);
  ds_retrieve.set("hhblno2", srch_ed_hhblno.getValue());
  if (ds_selling.getRowCount() > 0 && $c.util.isEmpty($p, ds_selling.getCellData(0, "tabIndex"))) {
    $c.win.alert($p, "조회된 Selling데이터가 있습니다.\nSelling데이터가 0건일 경우 조회가능합니다.");
  } else {
    $c.sbm.execute($p, sbm_retrieveSelling);
  }
  if (ds_partner.getRowCount() > 0 && $c.util.isEmpty($p, ds_partner.getCellData(0, "tabIndex"))) {
    $c.win.alert($p, "조회된 Partner데이터가 있습니다.\nPartner데이터가 0건일 경우 조회가능합니다.");
  } else {
    $c.sbm.execute($p, sbm_retrievePartner);
  }
  if (ds_buying.getRowCount() > 0 && $c.util.isEmpty($p, ds_buying.getCellData(0, "tabIndex"))) {
    $c.win.alert($p, "조회된 Buying데이터가 있습니다.\nBuying데이터가 0건일 경우 조회가능합니다.");
  } else {
    $c.sbm.execute($p, sbm_retrieveBuying);
  }
  $c.gus.cfEnableObj($p, srch_ed_hhblno, true);
  $c.gus.cfEnableObj($p, cnd_lc_mhno2, true);
};
