scwin.f_Update = async function () {
  if ($c.util.isEmpty($p, ed_hheta.getValue())) {
    // 등록 화면에 필수인 ETD를 기준으로 잡았음.
    $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_003);
    return;
  }
  scwin.f_Set("UPDATE");
  await scwin.f_invoiceCheck();
  $c.gus.cfDisableObjects($p, [ed_hhbuyer, txt_hhbuyernm, btn_hhbuyer]);
  if ($c.util.isEmpty($p, lc_shhcucd.getValue())) {
    lc_shhcucd.setValue("USD");
  }
  if ($c.util.isEmpty($p, ed_shhcurdt.getValue())) {
    ed_shhcurdt.setValue(ed_hheta.getValue());
  }
  if ($c.util.isEmpty($p, lc_phhcucd.getValue())) {
    lc_phhcucd.setValue("USD");
  }
  if ($c.util.isEmpty($p, ed_phhcurdt.getValue())) {
    ed_phhcurdt.setValue(ed_hheta.getValue());
  }
  if ($c.util.isEmpty($p, lc_bhhcucd.getValue())) {
    lc_bhhcucd.setValue("USD");
  }
  if ($c.util.isEmpty($p, ed_bhhcurdt.getValue())) {
    ed_bhhcurdt.setValue(ed_hheta.getValue());
  }
  if (lc_hhbltype.getValue() != "B") {
    $c.gus.cfDisableObjects($p, [ed_mtwgt]); //cargo type bulk일때만 M/T칸 활성화
  } else {
    $c.gus.cfEnableObjects($p, [ed_mtwgt]);
    $c.gus.cfDisableObjects($p, [lc_hhbltype]); //처음 생성한 cargo type bulk일때는 cargo type 변경 못하게
  }
};
