scwin.dataSetDebug = async function (dataList, isDebug) {
  if (!isDebug) return;
  let str = "[[[[" + dataList.id + "]]]]]\n";
  let rc = dataList.getRowCount();
  let cols = dataList.getColumnCount();
  for (let r = 0; r < rc; r++) {
    for (let c = 0; c < cols; c++) {
      let colId = dataList.getColumnId(c);
      str += "[" + colId + "] " + dataList.getCellData(r, colId) + ", ";
    }
    str += "\n\n";
  }
  await $c.win.alert($p, str);
};
