        ds_ocMblhList.setCellData(mr, "mhlodcd", ed_hhlodcd.getValue()); //Loading
        ds_ocMblhList.setCellData(mr, "mhlodnm", txt_hhdiscnm.getValue()); //Loading						
        ds_ocMblhList.setCellData(mr, "mhdisccd", ed_hhdisccd.getValue()); //Discharge
        ds_ocMblhList.setCellData(mr, "mhdiscnm", txt_hhlodnm.getValue()); //Discharge																	
