scwin.f_Copy = function () {
  scwin.f_FieldClear();
  ds_ocContList.removeAll();
  ds_selling.removeAll();
  ds_partner.removeAll();
  ds_buying.removeAll();
  ds_ocMblhList.removeAll();
  ds_retrieveBooking.removeAll();
  ds_retrieveBooking.insertRow(0);
  ds_retrieveBooking.setRowPosition(0);
  ds_retrieveNo.removeAll();
  ds_retrieveNo.insertRow(0);
  ds_retrieveNo.setRowPosition(0);
  ds_hmhno.removeAll();
  ds_hmhno.insertRow();
  ds_hmhno.setRowPosition(0);
  $c.gus.cfEnableObj($p, cnd_ed_hhblno, true);
  $c.gus.cfEnableObj($p, cnd_lc_mhno, true);
  scwin.f_Set("CREATE");
  scwin.f_Check();
  if (ds_houseblList.getRowCount() != 0) {
    ds_houseblList.modifyRowStatus(0, "C"); // insert 로 변경.
    scwin.hhbkgno = ds_houseblList.getCellData(0, "hhbkgno");
    ds_houseblList.setCellData(0, "hhbkgno", "");
  }
  ed_creadyDt.setValue(""); // 22.11.29 Result Date 공란처리
  txt_hhmitem2.setValue(""); // 22.11.29 EDI ITEM 공란처리

  //COPY Consignee -> Customer 복사 기능 추가
  if ($c.util.isEmpty($p, ed_hhactcust.getValue())) {
    if (!$c.util.isEmpty($p, ed_hhccd.getValue())) {
      ed_hhactcust.setValue(ed_hhccd.getValue());
      scwin.f_PopUp('Customer', 'T');
    } else if (!$c.util.isEmpty($p, ed_hhncd.getValue())) {
      ed_hhactcust.setValue(ed_hhncd.getValue());
      scwin.f_PopUp('Customer', 'T');
    }
  }
  txt_blpic.setValue("");
  //기본으로 등록자 ID 기입 처리
  if ($c.util.isEmpty($p, ed_blpic.getValue())) {
    ed_blpic.setValue(scwin.userId);
    scwin.f_PopUp("B/L PIC", "T");
  }
};
