scwin.f_Delete = async function () {
  await scwin.f_invoiceCheck();
  if (scwin.invoiceCheck === "1") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_041, ["Invoice No", "delete"]);
    return;
  }
  if (ds_hitekContents.getRowCount() > 0) {
    await $c.gus.cfAlertMsg($p, cnd_ed_hhblno.getValue() + " : " + "동부하이텍 인터페이스");
  }
  var ok = await $c.win.confirm($p, E_MSG_CM_CRM_004); //삭제하시겠습니까?
  if (!ok) return;
  if (cnd_lc_mhno.getValue() != "NONE") {
    $c.gus.cfAlertMsg($p, E_MSG_CM_WRN_011, ["Document No"]); // 이미 존재하는 @입니다.
    return;
  }
  for (var i = ds_houseblList.getRowCount() - 1; i >= 0; i--) {
    ds_houseblList.deleteRow(i);
  }
  for (var i = ds_containerBookingList.getRowCount() - 1; i >= 0; i--) {
    ds_containerBookingList.deleteRow(i);
  }
  $c.sbm.execute($p, sbm_delete);
};

// ---------------------------------------------------------------------
// Freight 삭제
// ---------------------------------------------------------------------
scwin.f_FreightDelete = async function () {
  if (ds_selling.getRowCount() === 0 && ds_partner.getRowCount() === 0 && ds_buying.getRowCount() === 0) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Freight Information"]);
    return;
  }
  await scwin.f_invoiceCheck();
  if (scwin.invoiceCheck === "1") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_041, ["Invoice No", "delete"]);
    return;
  }
  var ok = await $c.win.confirm($p, MSG_CM_CRM_004);
  if (!ok) return;
  for (var i = ds_selling.getRowCount() - 1; i >= 0; i--) {
    ds_selling.deleteRow(i);
  }
  for (var i = ds_partner.getRowCount() - 1; i >= 0; i--) {
    ds_partner.deleteRow(i);
  }
  for (var i = ds_buying.getRowCount() - 1; i >= 0; i--) {
    ds_buying.deleteRow(i);
  }
  $c.sbm.execute($p, sbm_deleteFreight);
};

