// 행취소
//---------------------------------------------------------
scwin.f_deleteRow1 = function () {
  scwin.f_deleteRow(1);
};
scwin.f_deleteRowAll = function () {
  scwin.f_deleteRow(2);
};
scwin.f_cancelRow = function () {
  var disGubun = 1;
  if (disGubun === 1) {
    var status = ds_ocContList.getRowIndexByStatus(["C"]);
    ds_ocContList.removeRows(status);
    ds_ocContList.undoAll();
  }
};
