scwin.f_FdeleteRow = async function (disGubun) {
  switch (disGubun) {
    case 1:
      // Selling
      var rowPos1 = ds_selling.getRowPosition();
      for (var i = ds_selling.getRowCount() - 1; i >= 0; i--) {
        if (ds_selling.getCellData(i, "chk") == "T" || i == rowPos1) {
          if ($c.util.isEmpty($p, ds_selling.getCellData(i, "certiNo"))) {
            if (ds_selling.getRowStatus(i) === "C") {
              ds_selling.removeRow(i);
            } else {
              ds_selling.deleteRow(i);
            }
          } else {
            $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_041, ["Invoice No", "delete"]);
            return;
          }
        }
      } // end for
      //김진성요청으로 그리드 행 추가시 카운터 실시간 표시 4/8
      txt_totalSelling.setValue(ds_selling.getRowCount());
      break;
    case 2:
      // Partner
      var rowPos2 = ds_partner.getRowPosition();
      for (var i = ds_partner.getRowCount() - 1; i >= 0; i--) {
        if (ds_partner.getCellData(i, "chk") == "T" || i == rowPos2) {
          if ($c.util.isEmpty($p, ds_partner.getCellData(i, "certiNo"))) {
            if (ds_partner.getRowStatus(i) === "C") {
              ds_partner.removeRow(i);
            } else {
              ds_partner.deleteRow(i);
            }
          } else {
            $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_041, ["Invoice No", "delete"]);
            return;
          }
        }
      } // end for
      //김진성요청으로 그리드 행 추가시 카운터 실시간 표시 4/8
      txt_totalPartner.setValue(ds_partner.getRowCount());
      break;
    case 3:
      // Buying
      var rowPos3 = ds_buying.getRowPosition();
      for (var i = ds_buying.getRowCount() - 1; i >= 0; i--) {
        if (ds_buying.getCellData(i, "chk") == "T" || i == rowPos3) {
          if ($c.util.isEmpty($p, ds_buying.getCellData(i, "pchsCertiNo"))) {
            if (ds_buying.getCellData(i, "dcsnClsCd") == "확정") {
              $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_041, ["확정", "delete"]);
              return;
            } else {
              if (ds_buying.getRowStatus(i) === "C") {
                ds_buying.removeRow(i);
              } else {
                ds_buying.deleteRow(i);
              }
            }
          } else {
            $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_041, ["Invoice No", "delete"]);
            return;
          }
        }
      } // end for 
      //김진성요청으로 그리드 행 추가시 카운터 실시간 표시 4/8
      txt_totalBuying.setValue(ds_buying.getRowCount());
      break;
  }
};
