scwin.f_FcancelRow = async function (disGubun) {
  var ds;
  switch (disGubun) {
    case 1:
      ds = ds_selling;
      break;
    case 2:
      ds = ds_partner;
      break;
    case 3:
      ds = ds_buying;
      break;
  }
  if (!ds || ds.getRowCount() == 0) return;
  // 신규 행 제거 (역순)
  for (var i = ds.getRowCount() - 1; i >= 0; i--) {
    if (ds.getRowStatus(i) === "C") {
      ds.removeRow(i);
    }
  }
  //김진성요청으로 그리드 행 추가시 카운터 실시간 표시 4/8
  switch (disGubun) {
    case 1:
      txt_totalSelling.setValue(ds.getRowCount());
      break;
    case 2:
      txt_totalPartner.setValue(ds.getRowCount());
      break;
    case 3:
      txt_totalBuying.setValue(ds.getRowCount());
      break;
  }
  // 수정된 데이터 원복
  ds.undoAll();
};

