//---------------------------------------------------------
scwin.f_validate_freight = async function () {
  // Selling 필수 체크
  for (var i = 0; i < ds_selling.getRowCount(); i++) {
    if (ds_selling.getRowStatus(i) === "D") continue;
    if ($c.util.isEmpty($p, ds_selling.getCellData(i, "rsltsStdDt"))) {
      await $c.gus.cfAlertMsg($p, "Selling List의 " + (i + 1) + "번째 데이터에서 Result은(는) 필수 입력 항목입니다.");
      return false;
    }
    if ($c.util.isEmpty($p, ds_selling.getCellData(i, "bilgClntNo"))) {
      await $c.gus.cfAlertMsg($p, "Selling List의 " + (i + 1) + "번째 데이터에서 Customer은(는) 필수 입력 항목입니다.");
      return false;
    }
  }
  // Partner 필수 체크
  for (var i = 0; i < ds_partner.getRowCount(); i++) {
    if (ds_partner.getRowStatus(i) === "D") continue;
    if ($c.util.isEmpty($p, ds_partner.getCellData(i, "rsltsStdDt"))) {
      await $c.gus.cfAlertMsg($p, "Partner List의 " + (i + 1) + "번째 데이터에서 Result은(는) 필수 입력 항목입니다.");
      return false;
    }
    if ($c.util.isEmpty($p, ds_partner.getCellData(i, "bilgClntNo"))) {
      await $c.gus.cfAlertMsg($p, "Partner List의 " + (i + 1) + "번째 데이터에서 Customer은(는) 필수 입력 항목입니다.");
      return false;
    }
  }
  // Buying 필수 체크
  for (var i = 0; i < ds_buying.getRowCount(); i++) {
    if (ds_buying.getRowStatus(i) === "D") continue;
    if ($c.util.isEmpty($p, ds_buying.getCellData(i, "rsltsStdDt"))) {
      await $c.gus.cfAlertMsg($p, "Buying List의 " + (i + 1) + "번째 데이터에서 Result은(는) 필수 입력 항목입니다.");
      return false;
    }
    if ($c.util.isEmpty($p, ds_buying.getCellData(i, "pchsClntNo"))) {
      await $c.gus.cfAlertMsg($p, "Buying List의 " + (i + 1) + "번째 데이터에서 Customer은(는) 필수 입력 항목입니다.");
      return false;
    }
  }

  // Selling
  for (var i = ds_selling.getRowCount() - 1; i >= 0; i--) {
    var fareEngCd = ds_selling.getCellData(i, "fareEngCd");
    var sellAmt = Number(ds_selling.getCellData(i, "sellAmt") || 0);

    // F/CODE 공란 && Amount(W)=0 => 행 삭제
    if ($c.util.isEmpty($p, fareEngCd) && sellAmt === 0) {
      ds_selling.removeRow(i);
      continue;
    }

    // F/CODE 존재 && Amount(W)=0 => 경고
    if (!$c.util.isEmpty($p, fareEngCd) && sellAmt === 0) {
      await $c.win.alert($p, "Amount(W) 금액이 0입니다. \nSelling List " + (i + 1) + "번째 데이터를 확인하세요.");
      return false;
    }
    // 삭제 상태 행만 내부거래 체크
    var rowStatus = ds_selling.getRowStatus(i);
    if (rowStatus === "D") {
      await scwin.f_postDtChk(ds_selling.getCellData(i, "odrNo"), ds_selling.getCellData(i, "sellSeq"), ds_selling.getCellData(i, "kcomcd"), ds_selling.getCellData(i, "seaAirCls"), ds_selling.getCellData(i, "blNo"), ds_selling.getCellData(i, "mhno"));
      var isPostDt = ds_PostDtDataSet.getCellData(0, "col1");
      if (!$c.util.isEmpty($p, isPostDt)) {
        await $c.win.alert($p, "내부거래 확정 건 입니다. \nSelling List " + (i + 1) + "번째 데이터를 확인하세요.");
        return false;
      }
    }
  }

  // partner
  for (var i = ds_partner.getRowCount() - 1; i >= 0; i--) {
    var fareEngCd = ds_partner.getCellData(i, "fareEngCd");
    var sellAmt = Number(ds_partner.getCellData(i, "sellAmt") || 0);

    // F/CODE 공란 && Amount(W)=0 => 행 삭제
    if ($c.util.isEmpty($p, fareEngCd) && sellAmt === 0) {
      ds_partner.removeRow(i);
      continue;
    }

    // F/CODE 존재 && Amount(W)=0 => 경고
    if (!$c.util.isEmpty($p, fareEngCd) && sellAmt === 0) {
      await $c.win.alert($p, "Amount(W) 금액이 0입니다. \nPartner List " + (i + 1) + "번째 데이터를 확인하세요.");
      return false;
    }
    // 삭제 상태 행만 내부거래 체크
    var rowStatus = ds_partner.getRowStatus(i);
    if (rowStatus === "D") {
      await scwin.f_postDtChk(ds_partner.getCellData(i, "odrNo"), ds_partner.getCellData(i, "sellSeq"), ds_partner.getCellData(i, "kcomcd"), ds_partner.getCellData(i, "seaAirCls"), ds_partner.getCellData(i, "blNo"), ds_partner.getCellData(i, "mhno"));
      var isPostDt = ds_PostDtDataSet.getCellData(0, "col1");
      if (!$c.util.isEmpty($p, isPostDt)) {
        await $c.win.alert($p, "내부거래 확정 건 입니다. \nPartner List " + (i + 1) + "번째 데이터를 확인하세요.");
        return false;
      }
    }
  }

  // buying
  for (var i = ds_buying.getRowCount() - 1; i >= 0; i--) {
    var fareEngCd = ds_buying.getCellData(i, "fareEngCd");
    var pchsAmt = Number(ds_buying.getCellData(i, "pchsAmt") || 0);

    // F/CODE 공란 && Amount(W)=0 => 행 삭제
    if ($c.util.isEmpty($p, fareEngCd) && pchsAmt === 0) {
      ds_buying.removeRow(i);
      continue;
    }

    // F/CODE 존재 && Amount(W)=0 => 경고
    if (!$c.util.isEmpty($p, fareEngCd) && pchsAmt === 0) {
      await $c.win.alert($p, "Amount(W) 금액이 0입니다. \nBuying List " + (i + 1) + "번째 데이터를 확인하세요.");
      return false;
    }
    // 삭제 상태 행만 내부거래 체크
    var rowStatus = ds_buying.getRowStatus(i);
    if (rowStatus === "D") {
      await scwin.f_postDtChk(ds_buying.getCellData(i, "odrNo"), ds_buying.getCellData(i, "pchsSeq"), ds_buying.getCellData(i, "kcomcd"), ds_buying.getCellData(i, "seaAirCls"), ds_buying.getCellData(i, "blNo"), ds_buying.getCellData(i, "mhno"));
      var isPostDt = ds_PostDtDataSet.getCellData(0, "col1");
      if (!$c.util.isEmpty($p, isPostDt)) {
        await $c.win.alert($p, "내부거래 확정 건 입니다. \nBuying List " + (i + 1) + "번째 데이터를 확인하세요.");
        return false;
      }
    }
  }
  for (var i = 0; i < ds_selling.getRowCount(); i++) {
    if (ds_selling.getCellData(i, "vatYn") == 0 && ds_selling.getCellData(i, "vatAmt") > 0) {
      await $c.win.alert($p, "영세코드와 부가세 금액은 함께 입력될 수 없습니다. \nSelling List " + (i + 1) + "번째 데이터를 확인하세요.");
      gr_selling.focus();
      gr_selling.setFocusedCell(i, "vatAmt", true);
      return false;
    }
    if (ds_selling.getCellData(i, "vatYn") == 1) {
      if (Math.abs(Math.round(ds_selling.getCellData(i, "sellAmt") * 0.1) - ds_selling.getCellData(i, "vatAmt")) > 1) {
        await $c.win.alert($p, "VAT 금액은 Amount(W)금액의 10%입니다. \nSelling List " + (i + 1) + "번째 금액을 확인하세요.");
        gr_selling.focus();
        gr_selling.setFocusedCell(i, "vatAmt", true);
        return false;
      }
    }
  }
  for (var i = 0; i < ds_buying.getRowCount(); i++) {
    if (ds_buying.getCellData(i, "vatYn") == 0 && ds_buying.getCellData(i, "vat") > 0) {
      await $c.win.alert($p, "영세코드와 부가세 금액은 함께 입력될 수 없습니다. \nBuying List " + (i + 1) + "번째 데이터를 확인하세요.");
      gr_buying.focus();
      gr_buying.setFocusedCell(i, "vat", true);
      return false;
    }
  }
  return true;
};
//---------------------------------------------------------
// function name : f_validate
// function desc : 
//---------------------------------------------------------
scwin.f_validate = async function () {
  if (!(await $c.gus.cfValidate($p, [ed_hhetd, ed_hhondt, ed_hheta, ed_hhisudt, ed_creadyDt]))) {
    //validExp 가 yes일때 check
    return false;
  }
  if ($c.util.isEmpty($p, ed_hheta.getValue())) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["ETA"]);
    scwin.cfViewTab(0);
    ed_hheta.focus();
    return false;
  }

  // ETD가 저장일로부터 3개월 초과 미래 불가
  if ($c.gus.cfMonthsBetween($p, scwin.strCurDate.toDate(), ed_hhetd.getValue().toDate()) > 3) {
    await $c.win.alert($p, "ETD가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없습니다.");
    scwin.cfViewTab(0);
    ed_hhetd.focus();
    return false;
  }

  // ETA가 저장일로부터 3개월 초과 미래 불가
  if ($c.gus.cfMonthsBetween($p, scwin.strCurDate.toDate(), ed_hheta.getValue().toDate()) > 3) {
    await $c.win.alert($p, "ETA가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없습니다.");
    scwin.cfViewTab(0);
    ed_hheta.focus();
    return false;
  }

  // ETD가 3년 초과 과거 불가
  if ($c.gus.cfYearsBetween($p, ed_hhetd.getValue().toDate(), scwin.strCurDate.toDate()) > 3) {
    await $c.win.alert($p, "ETD가 3년 이상의 과거 일 수 없습니다.");
    scwin.cfViewTab(0);
    ed_hhetd.focus();
    return false;
  }

  // ETA가 3년 초과 과거 불가
  if ($c.gus.cfYearsBetween($p, ed_hheta.getValue().toDate(), scwin.strCurDate.toDate()) > 3) {
    await $c.win.alert($p, "ETA가 3년 이상의 과거 일 수 없습니다.");
    scwin.cfViewTab(0);
    ed_hheta.focus();
    return false;
  }

  // ETA-ETD(transit time) 150일 초과 불가 (ETA-ETD + 1 <= 150  =>  (ETA-ETD) <= 149)
  if (WebSquare.date.dateDiff(ed_hhetd.getValue(), ed_hheta.getValue()) > 149) {
    await $c.win.alert($p, "ETA-ETD(transit time)가 150일을 초과할 수 없습니다.");
    scwin.cfViewTab(0);
    ed_hhetd.focus();
    return false;
  }
  if ($c.util.isEmpty($p, txt_hhmitem2.getValue())) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["EDI ITEM"]);
    scwin.cfViewTab(0);
    txt_hhmitem2.focus();
    return false;
  }
  if ($c.util.isEmpty($p, ed_hhbuyer.getValue())) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Department"]);
    scwin.cfViewTab(0);
    ed_hhbuyer.focus();
    return false;
  }

  // EDI ITEM 글자수 및 특수문자 여부 CHECK
  if (!ilcommon.cf_ChkInputOnlyNumberAndAlphabet(txt_hhmitem2.getValue())) {
    await $c.win.alert($p, "EDI ITEM에 특수문자만 입력은 불가능합니다.");
    return false;
  }
  if ($c.gus.cfGetByteLength($p, txt_hhmitem2.getValue()) < 2) {
    await $c.win.alert($p, "EDI ITEM에 2글자 이상을 입력하셔야합니다.");
    return false;
  }
  if ($c.util.isEmpty($p, lc_contractno.getValue())) {
    await $c.win.alert($p, "계약은 필수항목 입니다. Customer를 확인하세요.");
    scwin.cfViewTab(0);
    ed_hhactcust.focus();
    return false;
  }
  var custInfo = await scwin.f_commCodeSync("ilCommonEBC", "retriveCustomerInfo", ed_hhactcust.getValue());
  if (custInfo && custInfo.length > 0) {
    if (ed_hhbuyer.getValue() !== custInfo[0].col1) {
      await $c.gus.cfAlertMsg($p, scwin.MSG_LO_WRN_007);
      scwin.cfViewTab(0);
      ed_hhbuyer.focus();
      return false;
    }
  }
  for (var i = 0; i < ds_buying.getRowCount(); i++) {
    if (ds_buying.getCellData(i, "pchsTyp") == "3" && $c.util.isEmpty($p, ds_buying.getCellData(i, "sellDeptCd"))) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Inner Department"]); //@는 필수입력항목입니다.
      gr_buying.focus();
      gr_buying.setFocusedCell(i, "sellDeptCd", true); // forcus
      return false;
    }
  }
  return true;
};

