//-------------------------------------------------------------------------
// ExRate Grid 공통 (Selling/Buying/Partner)
//-------------------------------------------------------------------------
scwin.f_loadExRateGrid = function (ds, target) {
  var rp = ds.getRowPosition();
  var houseCur = target == "SELLING" ? lc_shhcucd.getValue() : target == "PARTNER" ? lc_phhcucd.getValue() : lc_bhhcucd.getValue();
  var houseRate = target == "SELLING" ? ed_shhexrate.getValue() : target == "PARTNER" ? ed_phhexrate.getValue() : ed_bhhexrate.getValue();
  var rowCur = ds.getCellData(rp, "crcCd");
  if (houseCur == rowCur) {
    ds.setCellData(rp, "exRate", houseRate);
    return;
  }

  // 이미 환율이 있으면 조회 불필요
  var exRate = ds.getCellData(rp, "exRate");
  if (exRate != "" && exRate != "0") return;
  var param1 = rowCur;
  var param2 = target == "SELLING" ? ed_shhcurdt.getValue() : target == "PARTNER" ? ed_phhcurdt.getValue() : ed_bhhcurdt.getValue();
  var param3 = target == "SELLING" ? lc_shhexgb.getValue() : target == "PARTNER" ? lc_phhexgb.getValue() : lc_bhhexgb.getValue();
  scwin._comboTarget = target; // "SELLING" | "BUYING" | "PARTNER"
  scwin._exRateRow = rp;
  scwin._exRateCur = param1;
  scwin.f_commCode("ilCommonEBC", "retrieveExRate", param1, param2, param3);
};
