//-------------------------------------------------------------------------
//Tariff All 가져오기
//------------------------------------------------------------------------- 
scwin.f_tariffAllLoading = async function (tabNo) {
  function getCnt(typeComp, qtyComp) {
    var t = typeComp ? String(typeComp.getValue() || "").trim() : "";
    var q = qtyComp ? String(qtyComp.getValue() || "").trim() : "";
    if (t != "" && q != "" && q != "0") return t;
    return "0";
  }
  var cnt1 = getCnt(ed_hhcnt1type, ed_hhcnt1);
  var cnt2 = getCnt(ed_hhcnt2type, ed_hhcnt2);
  var cnt3 = getCnt(ed_hhcnt3type, ed_hhcnt3);
  var cnt4 = getCnt(ed_hhcnt4type, ed_hhcnt4);

  // 기존 데이터 존재 여부 체크
  if (tabNo == "0") {
    if (ds_selling.getRowCount() > 0) {
      $c.gus.cfAlertMsg($p, E_MSG_CM_WRN_011, ["Selling Information"]);
      return;
    }
  } else if (tabNo == "1") {
    if (ds_partner.getRowCount() > 0) {
      $c.gus.cfAlertMsg($p, E_MSG_CM_WRN_011, ["Partner Information"]);
      return;
    }
  } else if (tabNo == "2") {
    if (ds_buying.getRowCount() > 0) {
      $c.gus.cfAlertMsg($p, E_MSG_CM_WRN_011, ["Buying Information"]);
      return;
    }
  }
  if (!(await $c.win.confirm($p, E_MSG_CM_CRM_001))) return;
  ds_retrieveTariff.removeAll();
  ds_resultTariff.removeAll();
  const r = ds_retrieveTariff.insertRow(0);
  var kcomcd = scwin.hd_kcomcd;
  var apdt = ed_hhetd.getValue();
  var item = scwin.hd_hhitem;
  var dang = scwin.hd_hhdanggb;
  var comm = scwin.hd_commcustomer;

  // 탭별 세팅
  if (tabNo == "0") {
    // Selling
    ds_retrieveTariff.setCellData(r, "fgubn", "1");
    ds_retrieveTariff.setCellData(r, "customer", ed_hhactcust.getValue());
    ds_retrieveTariff.setCellData(r, "partner", "");
    ds_retrieveTariff.setCellData(r, "liner", ed_hhliner.getValue());
    ds_retrieveTariff.setCellData(r, "transTariffYn", "Y");
    ds_retrieveTariff.setCellData(r, "blNo", cnd_ed_hhblno.getValue());
    ds_retrieveTariff.setCellData(r, "mhno", cnd_lc_mhno.getValue());
  } else if (tabNo == "1") {
    // Partner
    ds_retrieveTariff.setCellData(r, "fgubn", "3");
    ds_retrieveTariff.setCellData(r, "customer", "");
    ds_retrieveTariff.setCellData(r, "partner", ed_hhagent.getValue());
    ds_retrieveTariff.setCellData(r, "liner", "");
    ds_retrieveTariff.setCellData(r, "transTariffYn", "N");
    ds_retrieveTariff.setCellData(r, "blNo", "");
    ds_retrieveTariff.setCellData(r, "mhno", "");
  } else if (tabNo == "2") {
    // Buying
    ds_retrieveTariff.setCellData(r, "fgubn", "2");
    ds_retrieveTariff.setCellData(r, "customer", ed_hhactcust.getValue());
    ds_retrieveTariff.setCellData(r, "partner", "");
    ds_retrieveTariff.setCellData(r, "liner", ed_hhliner.getValue());
    ds_retrieveTariff.setCellData(r, "transTariffYn", "Y");
    ds_retrieveTariff.setCellData(r, "blNo", cnd_ed_hhblno.getValue());
    ds_retrieveTariff.setCellData(r, "mhno", cnd_lc_mhno.getValue());
  }

  // 공통 세팅
  ds_retrieveTariff.setCellData(r, "kcomcd", kcomcd);
  ds_retrieveTariff.setCellData(r, "apdt", apdt);
  ds_retrieveTariff.setCellData(r, "loading", ed_hhlodcd.getValue());
  ds_retrieveTariff.setCellData(r, "discharge", ed_hhdisccd.getValue());
  ds_retrieveTariff.setCellData(r, "item", item);
  ds_retrieveTariff.setCellData(r, "container1", cnt1);
  ds_retrieveTariff.setCellData(r, "container2", cnt2);
  ds_retrieveTariff.setCellData(r, "container3", cnt3);
  ds_retrieveTariff.setCellData(r, "container4", cnt4);
  ds_retrieveTariff.setCellData(r, "cbgubn", "C");
  ds_retrieveTariff.setCellData(r, "incoterm", "");
  ds_retrieveTariff.setCellData(r, "userid", scwin.userId);
  ds_retrieveTariff.setCellData(r, "dangerous", dang);
  ds_retrieveTariff.setCellData(r, "commcustomer", comm);
  ds_retrieveTariff.setCellData(r, "flag", "1");
  await $c.sbm.execute($p, sbm_retrieveTariff);
  if (ds_resultTariff.getRowCount() === 0) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_WRN_002);
    return;
  }
  if (!$c.win.confirm($p, E_MSG_CM_CRM_001)) {
    //저장하시겠습니까?	
    return;
  }
  if (tabNo == "0") {
    for (var i = 0; i < ds_resultTariff.getRowCount(); i++) {
      scwin.f_addRow(1); //kcomcd,blno,mhno,orderno,locptncls,mblhblcls,seaaircls,ppcccls,customer,customer name,실적일,inpid
      ds_selling.setCellData(i, "fareEngCd", ds_resultTariff.getCellData(i, "fareEngCd")); // fareEngCd	

      scwin.f_PopUpGrid("SellingFcode", i, "T", "F"); //sellitemcd,faregrpcd,vatyn										
      ds_selling.setCellData(i, "crcCd", ds_resultTariff.getCellData(i, "crcCd")); //cur
      ds_selling.setCellData(i, "fareUnit", ds_resultTariff.getCellData(i, "fareUnit")); //unit

      scwin.f_packageRateSellingLoading(i, ""); //package,rate

      ds_selling.setCellData(i, "sellUpr", ds_resultTariff.getCellData(i, "amount")); //rate						

      scwin.f_sellingAmtFcrc(i, "", ""); //amount(외화)	
      scwin.f_ExRateSellingGridLoading(); //ex-rate 
      scwin.f_sellingAmt(i, "", ""); //amount(원화)	
      scwin.f_sellingVat(i, "", ""); //vat							
      scwin.f_sellingUsdAmt(i, "", ""); //auount($) 
    }

    // package 0 인것 삭제.	
    for (var i = ds_selling.getRowCount() - 1; i >= 0; i--) {
      if (ds_selling.getCellData(i, "chgWt") == "0") {
        ds_selling.removeRow(i);
      }
    }
  } else if (tabNo == "1") {
    for (var i = 0; i < ds_resultTariff.getRowCount(); i++) {
      scwin.f_addRow(2); //kcomcd,blno,mhno,orderno,locptncls,mblhblcls,seaaircls,ppcccls,customer,customer name,실적일,inpid
      ds_partner.setCellData(i, "fareEngCd", ds_resultTariff.getCellData(i, "fareEngCd")); // fareEngCd	
      ds_partner.setCellData(i, "drcrCls", "C");
      scwin.f_PopUpGrid("PartnerFcode", i, "T", "F"); //sellitemcd,faregrpcd,vatyn
      ds_partner.setCellData(i, "crcCd", ds_resultTariff.getCellData(i, "crcCd")); //cur
      ds_partner.setCellData(i, "fareUnit", ds_resultTariff.getCellData(i, "fareUnit")); //unit

      scwin.f_packageRatePartnerLoading(i, ""); //package,rate

      ds_partner.setCellData(i, "sellUpr", ds_resultTariff.getCellData(i, "amount")); //rate

      scwin.f_partnerAmtFcrc(i, "", ""); //amount(외화)	
      scwin.f_ExRatePartnerGridLoading(); //ex-rate 
      scwin.f_partnerAmt(i, "", ""); //amount(원화)				
      scwin.f_partnerUsdAmt(i, "", ""); //auount($)
    }

    // package 0 인것 삭제.	
    for (var i = ds_partner.getRowCount() - 1; i >= 0; i--) {
      if (ds_partner.getCellData(i, "chgWt") == "0") {
        ds_partner.removeRow(i);
      }
    }
  } else if (tabNo == "2") {
    for (var i = 0; i < ds_resultTariff.getRowCount(); i++) {
      scwin.f_addRow(3); //kcomcd,blno,mhno,orderno,locptncls,mblhblcls,seaaircls,ppcccls,customer,customer name,실적일,inpid
      ds_buying.setCellData(i, "fareEngCd", ds_resultTariff.getCellData(i, "fareEngCd")); // fareEngCd	
      ds_buying.setCellData(i, "pchsTyp", "1");
      scwin.f_PopUpGrid("BuyingFcode", i, "T", "F"); //sellitemcd,faregrpcd,vatyn
      ds_buying.setCellData(i, "crcCd", ds_resultTariff.getCellData(i, "crcCd")); //cur
      ds_buying.setCellData(i, "fareUnit", ds_resultTariff.getCellData(i, "fareUnit")); //unit

      scwin.f_packageRateBuyingLoading(i, ""); //package,rate

      ds_buying.setCellData(i, "pchsUpr", ds_resultTariff.getCellData(i, "amount")); //rate						

      scwin.f_buyingAmtFcrc(i, "", ""); //amount(외화)	
      scwin.f_ExRateBuyingGridLoading(); //ex-rate 
      scwin.f_buyingAmt(i, "", ""); //amount(원화)	
      scwin.f_buyingVat(i, "", ""); //vat							
      scwin.f_buyingUsdAmt(i, "", ""); //auount($) 
    }

    // package 0 인것 삭제.	
    for (var i = ds_buying.getRowCount() - 1; i >= 0; i--) {
      if (ds_buying.getCellData(i, "chgWt") == "0") {
        ds_buying.removeRow(i);
      }
    }
  }
};
