scwin.f_CustomerChange_callback = async function (rtnList) {
  if (!rtnList || rtnList[0] != "N/A") {
    return;
  }
  var oldCode = rtnList[1] || "";
  var newCode = rtnList[3] || "";
  var newName = rtnList[4] || "";
  if (scwin.tabNo == "0") {
    // Selling
    if (ds_selling.getRowCount() == 0) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Selling Information"]);
      return;
    }
    if (!(await $c.win.confirm($p, E_MSG_CM_CRM_001))) {
      return;
    }
    for (var i = 0; i < ds_selling.getRowCount(); i++) {
      if ($c.util.isEmpty($p, ds_selling.getCellData(i, "certiNo")) && ds_selling.getCellData(i, "bilgClntNo") == oldCode) {
        ds_selling.setCellData(i, "bilgClntNo", newCode);
        ds_selling.setCellData(i, "bilgClntNm", newName);
      }
    }
  } else if (scwin.tabNo == "1") {
    // Partner
    if (ds_partner.getRowCount() == 0) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Partner Information"]);
      return;
    }
    if (!(await $c.win.confirm($p, E_MSG_CM_CRM_001))) {
      return;
    }
    for (var i = 0; i < ds_partner.getRowCount(); i++) {
      if ($c.util.isEmpty($p, ds_partner.getCellData(i, "certiNo")) && ds_partner.getCellData(i, "bilgClntNo") == oldCode) {
        ds_partner.setCellData(i, "bilgClntNo", newCode);
        ds_partner.setCellData(i, "bilgClntNm", newName);
      }
    }
  } else if (scwin.tabNo == "2") {
    // Buying
    if (ds_buying.getRowCount() == 0) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Buying Information"]);
      return;
    }
    if (!(await $c.win.confirm($p, E_MSG_CM_CRM_001))) {
      return;
    }
    for (var i = 0; i < ds_buying.getRowCount(); i++) {
      if ($c.util.isEmpty($p, ds_buying.getCellData(i, "pchsCertiNo")) && ds_buying.getCellData(i, "pchsClntNo") == oldCode) {
        ds_buying.setCellData(i, "pchsClntNo", newCode);
        ds_buying.setCellData(i, "pchsClntNm", newName);
      }
    }
  } // end if 
};
