// 합계 계산
//---------------------------------------------------------
scwin.f_SellingSum = function () {
  let rc = ds_selling.getRowCount();
  let v_SellingSumAmount = 0;
  let v_SellingSumAmountW = 0;
  let v_SellingSumVat = 0;
  let v_SellingSumAmountUs = 0;
  let v_SellingSumKrw = 0;
  for (let i = 0; i < rc; i++) {
    if (ds_selling.getRowStatus(i) != "D") {
      // != "2"  삭제 제외 
      let amtF = Number(ds_selling.getCellData(i, "sellAmtFcrc") || 0);
      let amtW = Number(ds_selling.getCellData(i, "sellAmt") || 0);
      let vat = Number(ds_selling.getCellData(i, "vatAmt") || 0);
      let usd = Number(ds_selling.getCellData(i, "usdAmt") || 0);
      let crc = ds_selling.getCellData(i, "crcCd");
      v_SellingSumAmount += amtF;
      v_SellingSumAmountW += amtW;
      v_SellingSumVat += vat;
      v_SellingSumAmountUs += usd;
      if (crc === "KRW") {
        v_SellingSumKrw += amtW + vat;
      }
    }
  }
  ed_SellingSumAmount.setValue(v_SellingSumAmount);
  ed_SellingSumAmountW.setValue(v_SellingSumAmountW);
  ed_SellingSumVat.setValue(v_SellingSumVat);
  ed_SellingAmountSum.setValue(v_SellingSumAmountW + v_SellingSumVat);
};
