scwin.f_HawbNoChange = function () {
  if (cnd_ed_hhblno.getValue().trim() == "") return;

  // 팝업으로 넘길 데이터(필요시)
  var data = {
    "callbackFn": scwin.f_HawbNoChange_callback,
    "pBlno": cnd_ed_hhblno.getValue()
  };
  let opts = {
    id: "ilCommonHawbNoChange",
    popupName: "House B/L No Change",
    modal: true,
    type: "browserPopup",
    width: 460,
    height: 280,
    title: "House no Change"
    // callbackFn: "scwin.f_HawbNoChange_callback"
  };

  // 팝업 호출 (프로젝트 팝업 규격에 맞게 openPopup 사용)
  $c.win.openPopup($p, "/ui/il/common/xml/ilCommonHawbNoChange.xml",
  // 실제 팝업 xml로 교체
  opts,
  // OPTS
  data);
};
scwin.f_HawbNoChange_callback = async function (ret) {
  if (!ret || typeof ret === "undefined") {
    return;
  }
  const flag = (ret[0] || "").trim();
  const newblNo = (ret[1] || "").trim();
  if (!(flag === "N/A" && !$c.util.isEmpty($p, newblNo))) {
    return;
  }

  // 파라미터 DS 세팅
  const ds = ds_HblNoChangeParam;
  ds.removeAll(); // 컬럼 만들어져 있음. 

  const row = ds.insertRow(0);
  ds.setCellData(row, "odrNo", ds_houseblList.getCellData(ds_houseblList.getRowPosition(), "odrNo"));
  ds.setCellData(row, "kcomcd", scwin.hd_kcomcd); // 법인코드
  ds.setCellData(row, "blNo", cnd_ed_hhblno.getValue()); // bulk여부
  ds.setCellData(row, "newblNo", newblNo);
  ds.setCellData(row, "mhno", ds_houseblList.getCellData(ds_houseblList.getRowPosition(), "mhno")); // 변경할 부서  명

  // 저장 확인
  const ok = await $c.win.confirm($p, E_MSG_CM_CRM_001); // "저장하시겠습니까?"
  if (!ok) {
    return;
  }
  await $c.sbm.execute($p, sbm_HblNoChange);
  var spMsg = ds_HblNoChangeResult.getRowCount() > 0 ? ds_HblNoChangeResult.getCellData(0, "spMsg") : "";
  var spRtn = ds_HblNoChangeResult.getRowCount() > 0 ? ds_HblNoChangeResult.getCellData(0, "spRtn") : "-1";
  if (spRtn == "0") {
    cnd_ed_hhblno.setValue(newblNo);
    cnd_lc_mhno.focus();
    await $c.gus.cfAlertMsg($p, scwin.MSG_LO_WRN_007);
  } else if (spRtn == "-1") {
    await $c.win.alert($p, "Invoice가 존재합니다.");
  } else if (spRtn == "-2") {
    await $c.gus.cfAlertMsg($p, spMsg);
  } else {
    await $c.win.alert($p, "실패하였습니다.");
  }
};
