scwin.f_TextareaSave = function () {
  var shipTa = txt_hhs1; // Shipper
  var consTa = txt_hhc1; // Consignee
  var notiTa = txt_hhn1; // Notify
  var rmkTa = txt_hhrmk1; // Remark

  var s1 = shipTa && shipTa.getValue && shipTa.getValue() || "";
  var c1 = consTa && consTa.getValue && consTa.getValue() || "";
  var n1 = notiTa && notiTa.getValue && notiTa.getValue() || "";
  var r1 = rmkTa && rmkTa.getValue && rmkTa.getValue() || "";
  scwin.hhs = s1.toUpperCase().split("\n");
  scwin.hhc = c1.toUpperCase().split("\n");
  scwin.hhn = n1.toUpperCase().split("\n");
  scwin.rmkk = r1.split("\n");
  for (var i = 0; i < 5; i++) {
    if (scwin.hhs[i] === undefined) scwin.hhs[i] = "";
    if (scwin.hhc[i] === undefined) scwin.hhc[i] = "";
    if (scwin.hhn[i] === undefined) scwin.hhn[i] = "";
    if (scwin.rmkk[i] === undefined) scwin.rmkk[i] = "";
  }
};

