scwin.f_chgGridColumnToHouseBlDs = function (gubun, ds) {
  for (var i = 1; i <= ds.getRowCount(); i++) {
    ds.setCellData(i - 1, "kcomcd", scwin.hd_kcomcd);
    ds.setCellData(i - 1, "blNo", cnd_ed_hhblno.getValue()); //update일때.
    ds.setCellData(i - 1, "mhno", cnd_lc_mhno.getValue()); //update일때.
    ds.setCellData(i - 1, "odrNo", ds_houseblList.getCellData(ds_houseblList.getRowPosition(), "odrNo"));
    ds.setCellData(i - 1, "mblHblCls", "H"); //house/master
    ds.setCellData(i - 1, "seaAirCls", "S"); // sea/air
    ds.setCellData(i - 1, "ppccCls", ds_houseblList.getCellData(ds_houseblList.getRowPosition(), "hhpcgb")); //pp/cc

    ds.setCellData(i - 1, "inpid", scwin.userId);
    if (gubun == "0") {
      ds.setCellData(i - 1, "bilgClntNo", ed_hhactcust.getValue()); //CUSTOMER
      ds.setCellData(i - 1, "bilgClntNm", txt_hhactcustnm.getValue()); //CUSTOMER name
      if (ds_sellingUnit.getRowCount() > 0) ds.setCellData(i - 1, "fareUnit", ds_sellingUnit.getCellData(0, "code"));
      ds.setCellData(i - 1, "drcrCls", "D"); // DR/CR
      ds.setCellData(i - 1, "locPtnCls", "1"); //국내 : 1, 해외 :2
      ds.setCellData(i - 1, "exRateTyp", lc_shhexgb.getValue()); //exgb
    } else if (gubun == "1") {
      ds.setCellData(i - 1, "bilgClntNo", ed_hhagent.getValue());
      ds.setCellData(i - 1, "bilgClntNm", txt_hhagentnm.getValue()); //partner name

      if (ds_partnerUnit.getRowCount() > 0) ds.setCellData(i - 1, "fareUnit", ds_partnerUnit.getCellData(0, "code"));
      ds.setCellData(i - 1, "drcrCls", "C"); // DR/CR
      ds.setCellData(i - 1, "locPtnCls", "2"); //국내 : 1, 해외 :2
      ds.setCellData(i - 1, "exRateTyp", lc_phhexgb.getValue()); //exgb
    } else if (gubun == "2") {
      //ds.setCellData((i)-1, "pchsClntNo", ed_hhliner.getValue());
      //ds.setCellData((i)-1, "pchsClntNm", txt_hhlinernm.getValue());   //Liner name

      if (ds_buyingUnit.getRowCount() > 0) ds.setCellData(i - 1, "fareUnit", ds_buyingUnit.getCellData(0, "code"));
      ds.setCellData(i - 1, "pchsTyp", "1");
      ds.setCellData(i - 1, "drcrCls", "C"); // DR/CR
      ds.setCellData(i - 1, "locPtnCls", "1"); //국내 : 1, 해외 :2
      ds.setCellData(i - 1, "exRateTyp", lc_bhhexgb.getValue()); //exgb
    }
    ds.setCellData(i - 1, "rsltsStdDt", scwin.hd_creadyDt); //실적일
    //			            ds.setCellData((i)-1, "exRateTyp", lc_shhexgb.getValue());  //exgb

    ds.modifyRowStatus(i - 1, "C");
  }

  //unit처리.
  if (gubun == "0") {
    scwin.f_SellingSum();
  } else if (gubun == "1") {
    scwin.f_PartnerSum();
  } else if (gubun == "2") {
    scwin.f_BuyingSum();
  }
};
