// gr_selling event=OnExit(Row,Colid,olddata)
scwin.gr_selling_oneditend = function (rowIndex, columnIndex, value) {
  var row = rowIndex;
  var col = gr_selling.getColumnID(columnIndex);
  var olddata = ds_selling.getCellData(row, col);
  if (row < 0 || ds_selling.getRowCount() <= row) return;
  switch (col) {
    case "bilgClntNo":
      if (olddata == value) break;
      if (!$c.util.isEmpty($p, value)) {
        ds_selling.setCellData(row, "bilgClntNo", value);
        ds_selling.setCellData(row, "bilgClntNm", "");
        scwin.customerSelected = false;
        scwin.f_PopUpGrid("SellingCustomer", row, "T", "F", "F");
        $p.setTimeout(function () {
          if (!scwin.customerSelected) {
            ds_selling.setCellData(row, "bilgClntNo", "");
            ds_selling.setCellData(row, "bilgClntNm", "");
          }
        }, 0);
      } else {
        ds_selling.setCellData(row, "bilgClntNo", "");
        ds_selling.setCellData(row, "bilgClntNm", "");
      }
      break;
    case "fareEngCd":
      if (olddata == value.toUpperCase()) break;
      if (!$c.util.isEmpty($p, value)) {
        ds_selling.setCellData(row, "fareEngNm", "");
        ds_selling.setCellData(row, "fareEngCd", value.toUpperCase());
        scwin.fcodeSelected = false;
        scwin.f_PopUpGrid("SellingFcode", row, "T", "F", "F");
        $p.setTimeout(function () {
          if (!scwin.fcodeSelected) {
            ds_selling.setCellData(row, "fareEngCd", "");
            ds_selling.setCellData(row, "fareEngNm", "");
          }
        }, 0);
      } else {
        ds_selling.setCellData(row, "fareEngCd", "");
        ds_selling.setCellData(row, "fareEngNm", "");
      }
      break;
    case "crcCd":
    case "chgWt":
    case "sellUpr":
      ds_selling.setCellData(row, col, value);
      scwin.f_sellingAmtFcrc(row, col, olddata);
      scwin.f_sellingAmt(row, col, olddata);
      scwin.f_sellingVat(row, col, olddata);
      scwin.f_sellingUsdAmt(row, col, olddata);
      break;
    case "exRate":
      ds_selling.setCellData(row, "exRate", value);
      scwin.f_sellingAmt(row, col, olddata);
      break;
    case "sellAmt":
      ds_selling.setCellData(row, "sellAmt", value);
      scwin.f_sellingVat(row, col, olddata);
      break;
    case "vatAmt":
      ds_selling.setCellData(row, "vatAmt", value);
      scwin.f_sellingUsdAmt(row, col, olddata);
      break;
    case "fareUnit":
      // gr_selling event=OnCloseUp(Row,Colid)

      if (olddata == value) break;
      ds_selling.setCellData(row, "fareUnit", value);
      scwin.f_packageRateSellingLoading(row, col);
      scwin.f_sellingTariffRateLoading();
      break;
  }
};
