scwin.gr_buying_oneditend = async function (rowIndex, columnIndex, value) {
  var row = rowIndex;
  var col = gr_buying.getColumnID(columnIndex);
  var olddata = ds_buying.getCellData(row, col);
  if (row < 0 || ds_buying.getRowCount() <= row) return;
  switch (col) {
    case "pchsClntNo":
      if (olddata == value) break;
      if (!$c.util.isEmpty($p, value)) {
        scwin.pno = value;
        // ds_buying.setCellData(row, "pchsClntNm", "");
        scwin.customerSelected = false;
        scwin.f_PopUpGrid("BuyingCustomer", row, "T", "F", "F");
        $p.setTimeout(function () {
          if (!scwin.customerSelected) {
            ds_buying.setCellData(rowIndex, "pchsClntNo", "");
            ds_buying.setCellData(rowIndex, "pchsClntNm", "");
          }
        }, 100);
        return false;
      } else {
        ds_buying.setCellData(row, "pchsClntNo", "");
        ds_buying.setCellData(row, "pchsClntNm", "");
      }
      break;
    case "fareEngCd":
      if (olddata == value.toUpperCase()) break;
      if (!$c.util.isEmpty($p, value)) {
        ds_buying.setCellData(row, "fareEngNm", "");
        ds_buying.setCellData(row, "fareEngCd", value.toUpperCase());
        scwin.fcodeSelected = false;
        scwin.f_PopUpGrid("BuyingFcode", row, "T", "F", "F");
        $p.setTimeout(function () {
          if (!scwin.fcodeSelected) {
            ds_buying.setCellData(row, "fareEngCd", "");
            ds_buying.setCellData(row, "fareEngNm", "");
          }
        }, 0);
      } else {
        ds_buying.setCellData(row, "fareEngCd", "");
        ds_buying.setCellData(row, "fareEngNm", "");
      }
      break;
    case "sellDeptCd":
      if (olddata == value) break;
      if (!$c.util.isEmpty($p, value)) {
        ds_buying.setCellData(row, "sellDeptNm", "");
        scwin.f_PopUpGrid("BuyingDept", row, "T", "F", "F");
      } else {
        ds_buying.setCellData(row, "sellDeptCd", "");
        ds_buying.setCellData(row, "sellDeptNm", "");
      }
      break;
    case "crcCd":
    case "chgWt":
    case "pchsUpr":
      ds_buying.setCellData(row, col, value);
      scwin.f_buyingAmtFcrc(row, col, olddata);
      scwin.f_buyingAmt(row, col, olddata);
      scwin.f_buyingVat(row, col, olddata);
      scwin.f_buyingUsdAmt(row, col, olddata);
      break;
    case "exRate":
      ds_buying.setCellData(row, "exRate", value);
      scwin.f_buyingAmt(row, col, olddata);
      scwin.f_buyingVat(row, col, olddata);
      break;
    case "pchsAmt":
      ds_buying.setCellData(row, "pchsAmt", value);
      scwin.f_buyingUsdAmt(row, col, olddata);
      scwin.f_buyingVat(row, col, olddata);
      break;
    case "vat":
      ds_buying.setCellData(row, "vat", value);
      scwin.f_buyingUsdAmt(row, col, olddata);
      scwin.f_buyingVat(row, col, olddata);
      break;
    case "fareUnit":
      // gr_buying  OnCloseUp(Row,Colid)

      if (olddata == value) break;
      ds_buying.setCellData(row, "fareUnit", value);
      scwin.f_packageRateBuyingLoading(row, col);
      await scwin.f_buyingTariffRateLoading();
      break;
    case "pchsTyp":
      // gr_buying  OnCloseUp(Row,Colid)
      // 내부부서일때 원본 로직 유지
      var pchsTyp = value;
      if (pchsTyp == "3") {
        ds_buying.setCellData(row, "pchsClntNo", scwin.v_clntNo);
        ds_buying.setCellData(row, "pchsClntNm", "");
        scwin.f_PopUpGrid("BuyingCustomer", row, "T", "F", "F");
      } else {
        ds_buying.setCellData(row, "pchsClntNo", "");
        ds_buying.setCellData(row, "pchsClntNm", "");
      }
      break;
  }
};
