scwin.gr_buying_onbeforeedit = function (rowIndex, columnIndex, value) {
  var col = gr_buying.getColumnID(columnIndex);
  // 항상 편집 불가 (AS-IS Edit=none)
  var alwaysReadOnly = ["column18", "pchsClntNm", "fareEngNm", "usdAmt", "pchsCertiNo", "trfUpr", "regName"];
  if (alwaysReadOnly.indexOf(col) > -1) {
    return false;
  }
  // pchsCertiNo 있으면 추가 보호
  var pchsCertiNo = ds_buying.getCellData(rowIndex, "pchsCertiNo");
  if (pchsCertiNo != null && pchsCertiNo != "") {
    var protectedCols = ["chk", "column18", "pchsTyp", "pchsClntNo", "fareEngCd", "crcCd", "fareUnit", "chgWt", "pchsUpr", "exRate", "pchsAmt", "vat", "sellDeptCd"];
    if (protectedCols.indexOf(col) > -1) {
      return false;
    }
  }
  // pchsAmtFcrc: crcCd가 KRW이면 편집 불가 (AS-IS 이중조건)
  if (col === "pchsAmtFcrc" && ds_buying.getCellData(rowIndex, "crcCd") === "KRW") {
    return false;
  }
  // sellDeptCd: pchsTyp가 3이 아니면 편집 불가 (AS-IS 이중조건)
  if (col === "sellDeptCd" && ds_buying.getCellData(rowIndex, "pchsTyp") != "3") {
    return false;
  }
};
